package com.radiacode.shared.ble

import kotlinx.coroutines.flow.Flow

/**
 * Платформенный транспорт BLE (общий контракт single-source).
 *
 * Реализации: Android — поверх Kable; iOS — поверх CoreBluetooth. Вся логика выше транспорта
 * (кодек команд, сборка/разбор кадров, репозитории) живёт в `commonMain` и работает с этим
 * интерфейсом.
 *
 * На данном этапе — только сканирование; подключение/запись добавятся следующими шагами.
 */
interface BleTransport {

    /**
     * Холодный поток найденных устройств RadiaCode.
     *
     * Подписка запускает сканирование, отмена сбора — останавливает его. Поток может эмитить
     * повторы одного устройства (режим allowDuplicates) — дедупликацию по
     * [RadiaCodeDevice.identifier] выполняет потребитель.
     */
    fun scan(): Flow<DiscoveredDevice>

    /**
     * Подключиться к ранее найденному устройству и вернуть готовое [DeviceConnection].
     *
     * Устройство должно быть встречено в недавнем [scan] (реализация хранит рекламный пакет по id,
     * т.к. сам [DiscoveredDevice] платформенного хендла не несёт).
     */
    suspend fun connect(device: DiscoveredDevice): DeviceConnection
}

