package com.radiacode.shared.ble

import com.juul.kable.Peripheral
import com.juul.kable.PlatformAdvertisement
import com.juul.kable.Scanner
import kotlinx.coroutines.flow.Flow
import kotlinx.coroutines.flow.mapNotNull
import kotlinx.coroutines.sync.Mutex
import kotlinx.coroutines.sync.withLock
import kotlin.uuid.Uuid

/**
 * Реализация [BleTransport] поверх Kable — общая для Android и iOS.
 *
 * Kable multiplatform: на Android уходит в `android.bluetooth`, на iOS — в CoreBluetooth.
 * Скан фильтруется по service UUID RadiaCode; каждый рекламный пакет разбирается общим
 * [RadiaCodeDiscovery] в [DiscoveredDevice]. Пакеты, не похожие на RadiaCode, отбрасываются.
 */
class KableBleTransport : BleTransport {

    private val serviceUuid = Uuid.parse(RadiaCodeBle.SERVICE_UUID)

    private val scanner = Scanner {
        filters {
            match {
                services = listOf(serviceUuid)
            }
        }
    }

    // id -> последняя реклама из скана: нужна, чтобы из [DiscoveredDevice] (без хендла) поднять Peripheral.
    private val advertisementsMutex = Mutex()
    private val advertisements = mutableMapOf<String, PlatformAdvertisement>()

    override fun scan(): Flow<DiscoveredDevice> =
        scanner.advertisements.mapNotNull { advertisement ->
            val device = RadiaCodeDiscovery.parse(
                name = advertisement.peripheralName,
                localName = advertisement.name,
                fallbackId = advertisement.identifier.toString(),
                rssi = advertisement.rssi,
            )
            if (device != null) {
                advertisementsMutex.withLock { advertisements[device.device.identifier] = advertisement }
            }
            device
        }

    override suspend fun connect(device: DiscoveredDevice): DeviceConnection {
        val advertisement = advertisementsMutex.withLock { advertisements[device.device.identifier] }
            ?: error("Устройство ${device.device.identifier} не найдено в последнем скане — сначала просканируйте")
        return KableDeviceConnection(Peripheral(advertisement), serviceUuid).also { it.open() }
    }
}

