package com.radiacode.shared.ble

/**
 * Чистый разбор результата скана в [DiscoveredDevice].
 *
 * Порт логики iOS `BluetoothManager.centralManager(_:didDiscover:advertisementData:rssi:)`:
 * выбираем имя (`name`, если оно содержит "RadiaCode", иначе `localName`), требуем префикс
 * "RadiaCode", парсим идентификатор из формата `RadiaCode-XXX#<id>`.
 *
 * Платформонезависим и тестируется без BLE-железа.
 */
object RadiaCodeDiscovery {

    /**
     * @param name имя периферии (iOS `CBPeripheral.name`; Android `Advertisement.peripheralName`)
     * @param localName локальное имя из рекламы (iOS `kCBAdvDataLocalName`; Android `Advertisement.name`)
     * @param fallbackId идентификатор платформы (UUID/MAC), если в имени нет `#<id>`
     * @param rssi уровень сигнала в dBm
     * @return [DiscoveredDevice] либо `null`, если это не устройство RadiaCode
     *
     * Примечание: iOS требует одновременно `name` и `localName` (`guard let`); здесь требование
     * ослаблено (берём любое доступное имя), т.к. скан уже отфильтрован по service UUID, а на
     * Android `localName`/`peripheralName` может отсутствовать.
     */
    fun parse(name: String?, localName: String?, fallbackId: String, rssi: Int): DiscoveredDevice? {
        val resolved = when {
            name != null && name.contains(RadiaCodeBle.DEFAULT_NAME) -> name
            localName != null -> localName
            else -> name
        } ?: return null

        if (!resolved.startsWith(RadiaCodeBle.DEFAULT_NAME)) return null

        val parts = resolved.split("#")
        val deviceId: String
        val deviceName: String
        if (parts.size == 2) {
            deviceId = parts[1]
            deviceName = parts[0]
        } else {
            deviceId = fallbackId
            deviceName = RadiaCodeBle.DEFAULT_NAME
        }

        return DiscoveredDevice(
            device = RadiaCodeDevice(identifier = deviceId, model = RadiaCodeModel.fromName(deviceName)),
            rssi = rssi,
        )
    }
}

