package com.radiacode.shared.ble

import kotlinx.coroutines.flow.Flow

/** Состояние подключения к прибору. */
enum class BleConnectionState { Connecting, Connected, Disconnecting, Disconnected }

/**
 * Активное подключение к одному прибору — «тупая труба» байтов.
 *
 * Здесь только запись пакетов и поток входящих уведомлений; кодек команд и их сериализация
 * (очередь) живут выше — над этим интерфейсом. Платформенный хендл (CoreBluetooth/Kable) спрятан
 * в реализации.
 */
interface DeviceConnection {

    /** Состояние подключения. */
    val state: Flow<BleConnectionState>

    /** Поток сырых уведомлений от прибора (по одному ATT-уведомлению на эмиссию). */
    val notifications: Flow<ByteArray>

    /** Пишет пакеты по очереди, с подтверждением (write-with-response). */
    suspend fun write(packets: List<ByteArray>)

    /** Разорвать подключение. */
    suspend fun disconnect()
}

═══════════════════════════════════════════ shared .../ble/KableDeviceConnection.kt ═══════════════════════════════════════════
package com.radiacode.shared.ble

import com.juul.kable.Characteristic
import com.juul.kable.Peripheral
import com.juul.kable.State
import com.juul.kable.WriteType
import com.juul.kable.indicate
import com.juul.kable.notify
import com.juul.kable.write
import com.juul.kable.writeWithoutResponse
import kotlinx.coroutines.flow.Flow
import kotlinx.coroutines.flow.map
import kotlin.uuid.Uuid

/**
 * Подключение к прибору поверх Kable [Peripheral]. Общее для Android и iOS.
 *
 * Создаётся [KableBleTransport]; [open] подключается и находит write/notify характеристики под
 * сервисом RadiaCode.
 */
internal class KableDeviceConnection(
    private val peripheral: Peripheral,
    private val serviceUuid: Uuid,
) : DeviceConnection {

    private lateinit var writeCharacteristic: Characteristic
    private lateinit var notifyCharacteristic: Characteristic

    /** Подключиться и найти характеристики записи/уведомлений. */
    suspend fun open() {
        peripheral.connect()
        val service = peripheral.services.value?.firstOrNull { it.serviceUuid == serviceUuid }
            ?: error("Сервис RadiaCode $serviceUuid не найден на устройстве")
        writeCharacteristic = service.characteristics.first {
            it.properties.write || it.properties.writeWithoutResponse
        }
        notifyCharacteristic = service.characteristics.first {
            it.properties.notify || it.properties.indicate
        }
    }

    override val state: Flow<BleConnectionState> =
        peripheral.state.map { state ->
            when (state) {
                is State.Connected -> BleConnectionState.Connected
                is State.Disconnecting -> BleConnectionState.Disconnecting
                is State.Disconnected -> BleConnectionState.Disconnected
                else -> BleConnectionState.Connecting
            }
        }

    override val notifications: Flow<ByteArray>
        get() = peripheral.observe(notifyCharacteristic)

    override suspend fun write(packets: List<ByteArray>) {
        packets.forEach { packet ->
            peripheral.write(writeCharacteristic, packet, WriteType.WithResponse)
        }
    }

    override suspend fun disconnect() {
        peripheral.disconnect()
    }
}

