/**
 * Тип отображения списка устройств.
 *
 * Состояния `BluetoothDisabled` / `NotAuthorized` (нужен статус адаптера) добавятся вместе с
 * этапом подключения — см. [DeviceListViewModel.connect].
 */
enum class DeviceListViewType { Normal, NoDevices }

/** Состояние экрана списка устройств. */
data class DeviceListState(
    val isSearching: Boolean = false,
    val devices: List<DiscoveredDevice> = emptyList(),
    val viewType: DeviceListViewType = DeviceListViewType.Normal,
)

/**
 * Общая ViewModel списка устройств.
 *
 * Построена на KMP-ObservableViewModel: [state] наблюдается нативно — в SwiftUI через `@StateViewModel`
 * (+ Observation), в Compose через `collectAsState`. Lifecycle и `viewModelScope` даёт базовый
 * [ViewModel] (scope отменяется при `clear()`).
 *
 */
class DeviceListViewModel(
    private val transport: BleTransport,
) : ViewModel() {

    /** Без аргументов — Kotlin-дефолты не видны из Swift, поэтому отдельный конструктор. */
    constructor() : this(KableBleTransport())

    private val found = LinkedHashMap<String, DiscoveredDevice>()

    private val _state = MutableStateFlow(viewModelScope, DeviceListState())

    @NativeCoroutinesState
    val state: StateFlow<DeviceListState> = _state.asStateFlow()

    private var scanJob: Job? = null
    private var notFoundJob: Job? = null

    init {
        println("[DeviceListViewModel] init: $this")
    }

    /** Старт сканирования. */
    fun start() {
        stop()
        found.clear()
        _state.value = DeviceListState(isSearching = true)
        scanJob = viewModelScope.coroutineScope.launch {
            transport.scan().collect { device ->
                found[device.device.identifier] = device
                _state.value = _state.value.copy(
                    devices = found.values.sortedByDescending { it.rssi },
                )
            }
        }
        startNotFoundCheck()
    }

    /** Перезапуск проверки «устройства не найдены» (кнопка «Повторить»). */
    fun retryNotFound() {
        startNotFoundCheck()
    }

    /** Остановка сканирования (например, при уходе с экрана). */
    fun stop() {
        scanJob?.cancel()
        scanJob = null
        notFoundJob?.cancel()
        notFoundJob = null
        _state.value = _state.value.copy(isSearching = false)
    }

    /**
     * Подключение к устройству.
     *
     * TODO(connect): не реализовано. Появится на этапе переноса подсистемы подключения
     * (DeviceConnectionManager): handshake SetExchange → config → firmware → ready.
     */
    @Suppress("UNUSED_PARAMETER")
    fun connect(device: RadiaCodeDevice) {
        // Заглушка: реальное подключение пока живёт в Swift; этот экран тестовый.
    }

    /** Kotlin-аналог `deinit`: вызывается, когда владелец очищает VM (см. также авт-отмену viewModelScope). */
    override fun onCleared() {
        println("[DeviceListViewModel] onCleared: $this")
        super.onCleared()
    }

    private fun startNotFoundCheck() {
        notFoundJob?.cancel()
        _state.value = _state.value.copy(viewType = DeviceListViewType.Normal)
        notFoundJob = viewModelScope.coroutineScope.launch {
            delay(NOT_FOUND_TIMEOUT_MS)
            if (found.isEmpty()) {
                _state.value = _state.value.copy(viewType = DeviceListViewType.NoDevices)
            }
        }
    }

    private companion object {
        const val NOT_FOUND_TIMEOUT_MS = 30_000L
    }
}

