package com.radiacode.shared.ble

import kotlinx.coroutines.flow.Flow

/** Состояние подключения к прибору. */
enum class BleConnectionState { Connecting, Connected, Disconnecting, Disconnected }

/**
 * Активное подключение к одному прибору — «тупая труба» байтов.
 *
 * Здесь только запись пакетов и поток входящих уведомлений; кодек команд и их сериализация
 * (очередь) живут выше — над этим интерфейсом. Платформенный хендл (CoreBluetooth/Kable) спрятан
 * в реализации.
 */
interface DeviceConnection {

    /** Состояние подключения. */
    val state: Flow<BleConnectionState>

    /** Поток сырых уведомлений от прибора (по одному ATT-уведомлению на эмиссию). */
    val notifications: Flow<ByteArray>

    /** Пишет пакеты по очереди, с подтверждением (write-with-response). */
    suspend fun write(packets: List<ByteArray>)

    /** Разорвать подключение. */
    suspend fun disconnect()
}

