/** Разрешения, нужные для BLE-скана, в зависимости от версии Android. */
private fun requiredBlePermissions(): Array<String> =
    if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.S) {
        arrayOf(Manifest.permission.BLUETOOTH_SCAN, Manifest.permission.BLUETOOTH_CONNECT)
    } else {
        arrayOf(Manifest.permission.ACCESS_FINE_LOCATION)
    }

private fun blePermissionsGranted(context: Context): Boolean =
    requiredBlePermissions().all {
        context.checkSelfPermission(it) == PackageManager.PERMISSION_GRANTED
    }

/**
 * Экран поиска устройств RadiaCode: кнопка скана + список найденных (модель, id, RSSI).
 *
 * Дедуп по [DiscoveredDevice.device] identifier, сортировка по убыванию RSSI. Сканирование живёт,
 * пока экран на экране и нажата кнопка; разрешения запрашиваются по версии API.
 */
@Composable
fun DeviceListScreen(transport: BleTransport, modifier: Modifier = Modifier) {
    val context = LocalContext.current
    var scanning by remember { mutableStateOf(false) }
    var hasPermission by remember { mutableStateOf(blePermissionsGranted(context)) }
    var error by remember { mutableStateOf<String?>(null) }
    val devices = remember { mutableStateMapOf<String, DiscoveredDevice>() }

    val permissionLauncher = rememberLauncherForActivityResult(
        ActivityResultContracts.RequestMultiplePermissions(),
    ) { result ->
        hasPermission = result.values.all { it }
        scanning = hasPermission
    }

    LaunchedEffect(scanning) {
        if (!scanning) return@LaunchedEffect
        error = null
        devices.clear()
        runCatching {
            transport.scan().collect { d -> devices[d.device.identifier] = d }
        }.onFailure { error = it.message ?: it::class.simpleName }
    }

    Column(modifier = modifier.fillMaxSize().systemBarsPadding().padding(16.dp)) {
        Row(
            modifier = Modifier.fillMaxWidth(),
            horizontalArrangement = Arrangement.SpaceBetween,
            verticalAlignment = Alignment.CenterVertically,
        ) {
            Text("Устройства RadiaCode", style = MaterialTheme.typography.titleMedium)
            Button(
                onClick = {
                    when {
                        scanning -> scanning = false
                        hasPermission -> scanning = true
                        else -> permissionLauncher.launch(requiredBlePermissions())
                    }
                },
            ) {
                Text(if (scanning) "Стоп" else "Сканировать")
            }
        }

        Spacer(Modifier.height(8.dp))

        if (scanning) {
            Row(verticalAlignment = Alignment.CenterVertically) {
                CircularProgressIndicator(modifier = Modifier.size(16.dp), strokeWidth = 2.dp)
                Spacer(Modifier.width(8.dp))
                Text("Поиск…", style = MaterialTheme.typography.bodySmall)
            }
            Spacer(Modifier.height(8.dp))
        }

        error?.let {
            Text(
                "Ошибка: $it",
                style = MaterialTheme.typography.bodySmall,
                color = MaterialTheme.colorScheme.error,
            )
            Spacer(Modifier.height(8.dp))
        }

        val sorted = devices.values.sortedByDescending { it.rssi }
        if (sorted.isEmpty()) {
            Box(Modifier.fillMaxSize(), contentAlignment = Alignment.Center) {
                Text(
                    if (scanning) "Устройства пока не найдены…" else "Нажмите «Сканировать»",
                    style = MaterialTheme.typography.bodyMedium,
                )
            }
        } else {
            LazyColumn(verticalArrangement = Arrangement.spacedBy(8.dp)) {
                items(sorted, key = { it.device.identifier }) { device -> DeviceRow(device) }
            }
        }
    }
}

@Composable
private fun DeviceRow(device: DiscoveredDevice) {
    Card(modifier = Modifier.fillMaxWidth()) {
        Column(Modifier.padding(12.dp)) {
            Text(device.device.model.displayName, style = MaterialTheme.typography.titleSmall)
            Text("id: ${device.device.identifier}", style = MaterialTheme.typography.bodySmall)
            Text("RSSI: ${device.rssi} dBm", style = MaterialTheme.typography.bodySmall)
        }
    }
}

