package com.radiacode.shared.core.device

import com.juul.kable.Scanner
import com.radiacode.shared.core.device.model.RadiaCodeDiscovery
import kotlinx.coroutines.flow.Flow
import kotlinx.coroutines.flow.mapNotNull
import kotlin.uuid.Uuid

/**
 * BLE-константы устройства RadiaCode.
 *
 * Порт `DeviceBluetoothConstants` / `RadiaCode.swift` из iOS-приложения.
 */
object RadiaCodeBle {

    /** UUID основного сервиса RadiaCode — по нему фильтруется поиск. */
    const val SERVICE_UUID: String = "E63215E5-7003-49D8-96B0-B024798FB901"
}

/**
 * Поиск приборов RadiaCode в эфире (первая обязанность iOS `BluetoothManager`).
 *
 * Контракт общий для платформ; реализация ([KableBleScanner]) поверх Kable уходит на Android в
 * `android.bluetooth`, на iOS — в CoreBluetooth. Подключение и обмен командами — отдельные слои
 * над этим (появятся следующими шагами).
 */
interface BleScanner {

    /**
     * Холодный поток найденных устройств. Подписка запускает поиск, отмена сбора — останавливает
     * его. Поток может повторять одно и то же устройство (новый пакет → свежий уровень сигнала);
     * схлопывание по [RadiaCodeDiscovery] (его `device.identifier`) выполняет потребитель.
     */
    fun scan(): Flow<RadiaCodeDiscovery>
}

/**
 * Реализация [BleScanner] поверх Kable — общая для Android и iOS.
 *
 * Поиск фильтруется по сервису RadiaCode; каждый найденный пакет разбирается
 * [RadiaCodeDiscovery.parse]. Пакеты, не похожие на RadiaCode, отбрасываются.
 */
class KableBleScanner : BleScanner {

    private val serviceUuid = Uuid.parse(RadiaCodeBle.SERVICE_UUID)

    private val scanner = Scanner {
        filters {
            match {
                services = listOf(serviceUuid)
            }
        }
    }

    override fun scan(): Flow<RadiaCodeDiscovery> =
        scanner.advertisements.mapNotNull { advertisement ->
            RadiaCodeDiscovery.parse(
                name = advertisement.peripheralName,
                localName = advertisement.name,
                peripheralId = advertisement.identifier.toString(),
                rssi = advertisement.rssi,
            )
        }
}

