package com.radiacode.shared.core.device.model

/**
 * Модель прибора RadiaCode
 */
sealed class RadiaCodeModel(val name: String) {
    data object RadiaCode101 : RadiaCodeModel("RadiaCode-101")
    data object RadiaCode102 : RadiaCodeModel("RadiaCode-102")
    data object RadiaCode103 : RadiaCodeModel("RadiaCode-103")
    data object RadiaCode103G : RadiaCodeModel("RadiaCode-103G")
    data object RadiaCode110 : RadiaCodeModel("RadiaCode-110")
    data object RadiaCodeZero : RadiaCodeModel("RadiaCode-Zero")
    data class Other(val rawName: String) : RadiaCodeModel(rawName)

    val family: RadiaCodeFamily
        get() = when (this) {
            RadiaCode101, RadiaCode102, RadiaCode103 -> RadiaCodeFamily.RadiaCode10x
            RadiaCode103G -> RadiaCodeFamily.RadiaCode103G
            RadiaCode110 -> RadiaCodeFamily.RadiaCode11x
            RadiaCodeZero -> RadiaCodeFamily.RadiaCode41x
            is Other -> when {
                rawName.startsWith("RadiaCode-10") -> RadiaCodeFamily.RadiaCode10x
                rawName.startsWith("RadiaCode-11") -> RadiaCodeFamily.RadiaCode11x
                rawName.startsWith("RadiaCode-41") -> RadiaCodeFamily.RadiaCode41x
                else -> RadiaCodeFamily.RadiaCode10x
            }
        }

    companion object {
        const val DEFAULT_NAME: String = "RadiaCode"

        /** Из BLE*/
        operator fun invoke(rawValue: String): RadiaCodeModel = when (rawValue) {
            "RadiaCode-101" -> RadiaCode101
            "RadiaCode-102" -> RadiaCode102
            "RadiaCode-103" -> RadiaCode103
            "RadiaCode-103G" -> RadiaCode103G
            "RadiaCode-110" -> RadiaCode110
            "RadiaCode Zero" -> RadiaCodeZero
            else -> Other(rawValue)
        }

        /** Из серийного кода */
        fun serialCode(serialCode: String): RadiaCodeModel = when (serialCode) {
            "101" -> RadiaCode101
            "102" -> RadiaCode102
            "103" -> RadiaCode103
            "103G" -> RadiaCode103G
            "110" -> RadiaCode110
            "Zero", "410" -> RadiaCodeZero
            else -> Other("RadiaCode-$serialCode")
        }
    }
}

