//  Radiacode
//
//  Created by Pavel Marinchenko on 17.03.2023.
//

enum DeviceBluetoothConstants {

    enum PeripheralAdvertisementKeys: String {
        case localName = "kCBAdvDataLocalName"
        case timestamp = "kCBAdvDataTimestamp"
        case connectable = "kCBAdvDataIsConnectable"
        case primaryPHY = "kCBAdvDataRxPrimaryPHY"
        case secondaryPHY = "kCBAdvDataRxSecondaryPHY"
        case manufacturer = "kCBAdvDataManufacturerData"
        case serviceUUIDs = "kCBAdvDataServiceUUIDs"
    }
}

