func centralManager(
    _ central: CBCentralManager,
    didDiscover peripheral: CBPeripheral,
    advertisementData: [String: Any],
    rssi RSSI: NSNumber
) {
    let localName = DeviceBluetoothConstants.PeripheralAdvertisementKeys.localName.rawValue

    guard let name = peripheral.name, let localName = advertisementData[localName] as? String else {
        return
    }

    let peripheralName = name.contains(RadiaCode.Model.defaultName) ? name : localName

    guard peripheralName.hasPrefix(RadiaCode.Model.defaultName) else {
        return
    }

    let splittedName = peripheralName.components(separatedBy: "#")

    let deviceId: String
    let deviceName: String

    if splittedName.count == 2 {
        deviceId = splittedName[1]
        deviceName = splittedName[0]
    } else {
        deviceId = peripheral.identifier.uuidString
        deviceName = RadiaCode.Model.defaultName
    }

    let foundDevice = RadiaCode(
        device: .init(identifier: deviceId, model: deviceName),
        signal: .init(doubleValue: RSSI.doubleValue),
        connection: peripheral
    )
    devicesObserver.send(foundDevice)
}

func centralManager(_ central: CBCentralManager, didConnect peripheral: CBPeripheral) {
    peripheral.discoverServices([Consts.radiaCodeServiceCBUUID])
    peripheral.readRSSI()
}

